private function Auditor_SyncOrganizations($sToken)
{
    $iSelectedOrgId = (int) $this->Get('organization');
    if ($iSelectedOrgId <= 0) {
        throw new Exception('Не выбрана организация');
    }
    $oOrg = MetaModel::GetObject('Organization', $iSelectedOrgId, false);
    if ($oOrg === null) {
        throw new Exception('Организация не найдена: '.$iSelectedOrgId);
    }
    $iOrgId = $oOrg->GetKey();
    $aBody = array(
        'name' => $oOrg->GetName(),
        'itopOrganizationId' => $iOrgId,
    );

    $sBaseUrl = getenv('AUDITOR_SERVICE_URL');
    $sUrl = rtrim($sBaseUrl, '/').'/internal/tenants';

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось синхронизировать организацию: '.curl_error($ch));
    }
    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus !== 201 && $iStatus !== 200) {
        IssueLog::Error('Не удалось синхронизировать организацию. HTTP '.$iStatus.': '.$sResult);
        return;
    }

    $mData = json_decode($sResult, true);
    if (is_array($mData)) {
        $iTenantId = (int) reset($mData);
    } else {
        $iTenantId = (int) $sResult;
    }

    if ($iTenantId > 0 && (int)$oOrg->Get('auditor_tenant_id') === 0) {
        $oOrg->Set('auditor_tenant_id', $iTenantId);
        $oOrg->AllowWrite();
        $oOrg->DBUpdate();
    }
}

