private function Auditor_CreateAudit($sToken)
{
    $iAgentId = $this->Get('agent');
    $oAgent = MetaModel::GetObject('AuditAgent', $iAgentId, false);
    if (!$oAgent) {
        throw new Exception('Агент не найден');
    }

    $oUser = UserRights::GetUserObject();
    if (!$oUser) {
        throw new Exception('Пользователь не определен');
    }

    $iContactId = $oUser->Get('contactid');
    if (empty($iContactId)) {
        throw new Exception('У текущего пользователя не задан контакт');
    }

    $oPerson = MetaModel::GetObject('Person', $iContactId, false);
    if (!$oPerson) {
        throw new Exception('Контакт пользователя не найден');
    }

    $iOrgId = $oPerson->Get('org_id');
    if (empty($iOrgId)) {
        throw new Exception('У пользователя не указана организация');
    }

    $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
    if (!$oOrg) {
        throw new Exception('Организация не найдена');
    }

    $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
    if ($iTenantId <= 0) {
        throw new Exception('Организация не синхронизирована с сервисом аудита');
    }

    $oExtUsers = new DBObjectSet(
        DBObjectSearch::FromOQL('SELECT UserExternal WHERE contactid = :cid'),
        array(),
        array('cid' => $iContactId)
    );

    $oExtUser = $oExtUsers->Fetch();
    if (!$oExtUser) {
        throw new Exception('Внешний пользователь для этого контакта не найден. Выполните синхронизацию пользователя.');
    }

    $oMappingSet = new DBObjectSet(
        DBObjectSearch::FromOQL('SELECT AuditUserMapping WHERE user = :uid'),
        array(),
        array('uid' => $oExtUser->GetKey())
    );

    $oMapping = $oMappingSet->Fetch();
    $iAuditorUserId = $oMapping ? (int) $oMapping->Get('auditor_user_id') : 0;
    if ($iAuditorUserId <= 0) {
        throw new Exception('Не найден идентификатор пользователя в системе аудита. Выполните синхронизацию пользователя.');
    }

    if ((int) $oAgent->Get('organization') !== (int) $iOrgId) {
        throw new Exception('Агент не принадлежит организации текущего пользователя');
    }

    $sPublicId = $oAgent->Get('public_id');
    if (empty($sPublicId)) {
        throw new Exception('У агента не задан идентификатор');
    }

    $aBody = array(
        'tenantId' => $iTenantId,
        'initiatedById' => $iAuditorUserId,
        'agentPublicId' => $sPublicId,
    );
    $sBaseUrl = getenv('AUDITOR_SERVICE_URL');
    $sUrl = rtrim($sBaseUrl, '/').'/internal/audits';
    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));
    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось создать аудит: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus !== 201 && $iStatus !== 200) {
        throw new Exception('Не удалось создать аудит. HTTP '.$iStatus.': '.$sResult);
    }
}

protected function AfterInsert()
{
    parent::AfterInsert();
    if (!UserRights::IsAdministrator()) {
        IssueLog::Error('Синхронизация NVD доступна только администратору');
        return;
    }
    try {
        $sToken = AuditAgentToken::Auditor_StaticGetServiceAccessToken();
        $this->Nvd_CallSyncApi($sToken);
    } catch (Exception $e) {
        IssueLog::Error('Синхронизация NVD не выполнена: '.$e->getMessage());
    }
}

private function Nvd_CallSyncApi($sToken)
{
    $sType = $this->Get('sync_type');
    $sEndpoint = ($sType === 'incremental') ? 'incremental' : 'bootstrap';
    $sBaseUrl = getenv('ANALYZER_SERVICE_URL');
    $sUrl = rtrim($sBaseUrl, '/').'/api/nvd/'.$sEndpoint;

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, '{}');

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось выполнить запрос синхронизации NVD: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Синхронизация NVD завершилась с ошибкой. HTTP '.$iStatus.': '.$sResult);
    }
}

protected function OnInsert()
{
    $sSel = (string) $this->Get('oval_feed_selection');
    $aParts = explode(':', $sSel, 2);
    if (count($aParts) !== 2 || $aParts[0] === '' || $aParts[1] === '') {
        throw new Exception('Некорректно выбрана целевая выгрузка OVAL');
    }
    $this->Set('oval_vendor', $aParts[0]);
    $this->Set('feed_path', $aParts[1]);
    parent::OnInsert();
}

protected function AfterInsert()
{
    parent::AfterInsert();
    if (!UserRights::IsAdministrator()) {
        IssueLog::Error('Импорт OVAL доступен только администратору');
        return;
    }
    try {
        $sToken = AuditAgentToken::Auditor_StaticGetServiceAccessToken();
        $this->Oval_CallRefreshApi($sToken);
    } catch (Exception $e) {
        IssueLog::Error('Импорт OVAL не выполнен: '.$e->getMessage());
    }
}

private function Oval_CallRefreshApi($sToken)
{
    $sVendor = (string) $this->Get('oval_vendor');
    $sFeedPath = trim((string) $this->Get('feed_path'));
    $aByVendor = static::Oval_GetAllowedPathsByVendor();
    if (!isset($aByVendor[$sVendor])) {
        throw new Exception('Неизвестный поставщик OVAL');
    }
    if (!in_array($sFeedPath, $aByVendor[$sVendor], true)) {
        throw new Exception('Недопустимый каталог выгрузки OVAL: '.$sFeedPath);
    }

    $sBaseUrl = getenv('ANALYZER_SERVICE_URL');
    if ($sBaseUrl === false || $sBaseUrl === '') {
        throw new Exception('Не задан адрес системы синхронизации (переменная окружения ANALYZER_SERVICE_URL)');
    }
    $sUrl = rtrim($sBaseUrl, '/').'/api/oval/'.rawurlencode($sVendor).'/refresh?feedPath='.rawurlencode($sFeedPath);

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Accept: application/json',
    ));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось запустить импорт OVAL: '.curl_error($ch));
    }
    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Не удалось запустить импорт OVAL. HTTP '.$iStatus.': '.$sResult);
    }
}

public function GetInitialStateAttributeFlags($sAttCode, &$aReasons = array())
{
    $iFlags = parent::GetInitialStateAttributeFlags($sAttCode, $aReasons);
    if ($sAttCode === 'remote_schedule_id') {
        $iFlags |= OPT_ATT_HIDDEN;
    }
    $sFreq = $this->Get('frequency');

    if (in_array($sAttCode, array('time_of_day','day_of_week','day_of_month','custom_cron'))) {
        $iFlags |= OPT_ATT_HIDDEN;
    }

    if ($sFreq === 'hourly') {
    } elseif ($sFreq === 'daily') {
        if ($sAttCode === 'time_of_day') {
            $iFlags &= ~OPT_ATT_HIDDEN;
        }
    } elseif ($sFreq === 'weekly') {
        if (in_array($sAttCode, array('time_of_day','day_of_week'))) {
            $iFlags &= ~OPT_ATT_HIDDEN;
        }
    } elseif ($sFreq === 'monthly') {
        if (in_array($sAttCode, array('time_of_day','day_of_month'))) {
            $iFlags &= ~OPT_ATT_HIDDEN;
        }
    } elseif ($sFreq === 'custom') {
        if ($sAttCode === 'custom_cron') {
            $iFlags &= ~OPT_ATT_HIDDEN;
        }
    }

    return $iFlags;
}

protected function AfterInsert()
{
    parent::AfterInsert();
    try {
        $sCron = $this->Nvd_BuildCronExpression();
        $this->Set('cron_expression', $sCron);
        $this->AllowWrite();
        $this->DBUpdate();
        $this->Nvd_PushCreateToAnalyzer($sCron);
    } catch (Exception $e) {
        IssueLog::Error('Создание расписания синхронизации NVD не выполнено: '.$e->getMessage());
    }
}

protected function AfterUpdate()
{
    parent::AfterUpdate();
    try {
        $sCron = $this->Nvd_BuildCronExpression();
        $this->Set('cron_expression', $sCron);
        $this->AllowWrite();
        $this->DBUpdate();

        $iRemoteId = (int) $this->Get('remote_schedule_id');
        if ($iRemoteId > 0) {
            $this->Nvd_PushUpdateToAnalyzer($iRemoteId, $sCron);
        } else {
            $this->Nvd_PushCreateToAnalyzer($sCron);
        }
    } catch (Exception $e) {
        IssueLog::Error('Обновление расписания синхронизации NVD не выполнено: '.$e->getMessage());
    }
}

private function Nvd_BuildCronExpression()
{
    $sFreq = $this->Get('frequency');
    $sTime = trim((string) $this->Get('time_of_day'));
    if ($sTime === '') {
        $sTime = '03:00';
    }
    if (!preg_match('/^([0-1]?[0-9]|2[0-3]):([0-5][0-9])$/', $sTime, $aMatches)) {
        throw new Exception('Некорректное время: '.$sTime);
    }
    $iHour = (int) $aMatches[1];
    $iMin = (int) $aMatches[2];

    $sSec = '0';
    $sMin = (string) $iMin;
    $sHour = (string) $iHour;
    $sDom = '*';
    $sMon = '*';
    $sDow = '*';

    if ($sFreq === 'hourly') {
        $sMin = '0';
        $sHour = '*';
    } elseif ($sFreq === 'daily') {
    } elseif ($sFreq === 'weekly') {
        $sDow = (string) $this->Get('day_of_week');
        if ($sDow === '' || $sDow === '0') {
            throw new Exception('Не выбран день недели для еженедельного расписания');
        }
    } elseif ($sFreq === 'monthly') {
        $iDom = (int) $this->Get('day_of_month');
        if ($iDom < 1 || $iDom > 31) {
            throw new Exception('Некорректный день месяца для ежемесячного расписания');
        }
        $sDom = (string) $iDom;
    } elseif ($sFreq === 'custom') {
        $sCustom = trim((string) $this->Get('custom_cron'));
        if ($sCustom === '') {
            throw new Exception('Для произвольного расписания не задано Cron-выражение');
        }

        return $sCustom;
    } else {
        throw new Exception('Неизвестная частота: '.$sFreq);
    }

    return sprintf('%s %s %s %s %s %s', $sSec, $sMin, $sHour, $sDom, $sMon, $sDow);
}

private function Nvd_GetServiceAccessToken()
{
    return AuditAgentToken::Auditor_StaticGetServiceAccessToken();
}

private function Nvd_PushCreateToAnalyzer($sCron)
{
    $bEnabled = (bool) $this->Get('enabled');

    $aBody = array(
        'cronExpression' => $sCron,
        'enabled' => $bEnabled,
    );

    $sBaseUrl = getenv('ANALYZER_SERVICE_URL');
    if (empty($sBaseUrl)) {
        throw new Exception('Не задан адрес системы синхронизации (переменная окружения ANALYZER_SERVICE_URL)');
    }

    $sUrl = rtrim($sBaseUrl, '/').'/api/nvd/schedules';
    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$this->Nvd_GetServiceAccessToken(),
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось создать расписание синхронизации: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus !== 201 && $iStatus !== 200) {
        throw new Exception('Не удалось создать расписание синхронизации. HTTP '.$iStatus.': '.$sResult);
    }

    $aData = json_decode($sResult, true);
    if (!is_array($aData) || !isset($aData['id'])) {
        throw new Exception('Некорректный ответ при создании расписания синхронизации: '.$sResult);
    }

    $this->Set('remote_schedule_id', (int) $aData['id']);
    $this->AllowWrite();
    $this->DBUpdate();
}

private function Nvd_PushUpdateToAnalyzer($iRemoteId, $sCron)
{
    $bEnabled = (bool) $this->Get('enabled');
    $sBaseUrl = getenv('ANALYZER_SERVICE_URL');
    if (empty($sBaseUrl)) {
        throw new Exception('Не задан адрес системы синхронизации (переменная окружения ANALYZER_SERVICE_URL)');
    }

    $sBaseUrl = rtrim($sBaseUrl, '/').'/api/nvd/schedules/'.$iRemoteId;
    $aBody = array('cronExpression' => $sCron);
    $ch = curl_init($sBaseUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_CUSTOMREQUEST, 'PATCH');
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$this->Nvd_GetServiceAccessToken(),
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));
    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось обновить расписание синхронизации: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Не удалось обновить расписание синхронизации. HTTP '.$iStatus.': '.$sResult);
    }

    $sAction = $bEnabled ? 'enable' : 'disable';
    $sUrl = $sBaseUrl.'/'.$sAction;
    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_CUSTOMREQUEST, 'PATCH');
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$this->Nvd_GetServiceAccessToken(),
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, '{}');
    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Не удалось изменить состояние расписания ('.$sAction.'): '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Не удалось изменить состояние расписания ('.$sAction.'). HTTP '.$iStatus.': '.$sResult);
    }
}

public function DisplayBareRelations(WebPage $oPage, $bEditMode = false)
{
    parent::DisplayBareRelations($oPage, $bEditMode);
    if ($bEditMode) {
        return;
    }

    $sStatus = (string)$this->Get('status');
    if ($sStatus === 'RUNNING' || $sStatus === 'PENDING') {
        $oPage->add_ready_script('setTimeout(function(){ location.reload(); }, 30000);');
    }
}
